import { useState, useEffect } from 'react';
import { Link, NavLink, useLocation } from 'react-router-dom';
import { Menu, X, Shield, LogIn } from 'lucide-react';

const LINKS = [
  {to:'/',l:'Home'},{to:'/about',l:'About'},{to:'/services',l:'Services'},
  {to:'/blog',l:'Blog'},{to:'/team',l:'Team'},{to:'/announcements',l:'News'},
  {to:'/careers',l:'Careers'},{to:'/contact',l:'Contact'},
];

export default function Navbar() {
  const [scrolled,setScrolled] = useState(false);
  const [open,setOpen] = useState(false);
  const loc = useLocation();
  useEffect(()=>{
    const fn=()=>setScrolled(window.scrollY>24);
    window.addEventListener('scroll',fn,{passive:true});
    fn(); return ()=>window.removeEventListener('scroll',fn);
  },[]);
  useEffect(()=>{setOpen(false)},[loc]);
  useEffect(()=>{document.body.style.overflow=open?'hidden':'';return()=>{document.body.style.overflow=''}},[open]);

  const scrolledOrOpen = scrolled || open;

  return (
    <>
      <nav style={{
        position:'fixed',top:0,left:0,right:0,zIndex:1000,height:62,
        background: scrolled?'rgba(255,255,255,0.97)':'transparent',
        backdropFilter: scrolled?'blur(16px)':'none',
        borderBottom: scrolled?'1px solid var(--rule)':'1px solid transparent',
        transition:'all 0.28s ease',
      }}>
        <div style={{maxWidth:1160,margin:'0 auto',padding:'0 20px',height:'100%',display:'flex',alignItems:'center',justifyContent:'space-between',gap:12}}>
          <Link to="/" style={{display:'flex',flexDirection:'column',flexShrink:0}}>
            <span style={{fontFamily:'var(--serif)',fontSize:'1.25rem',fontWeight:800,color:scrolled?'var(--ink)':'#fff',lineHeight:1,letterSpacing:'-0.02em',transition:'color 0.28s'}}>SYNNOVIQ</span>
            <span style={{fontSize:'0.5rem',fontWeight:700,letterSpacing:'0.22em',textTransform:'uppercase',color:scrolled?'var(--blue)':'rgba(255,255,255,0.55)',transition:'color 0.28s',marginTop:2}}>Technologies</span>
          </Link>

          {/* Desktop nav */}
          <ul style={{display:'flex',gap:2,listStyle:'none',flex:1,justifyContent:'center'}} className="hide-mobile">
            {LINKS.map(({to,l})=>(
              <li key={to}><NavLink to={to} end={to==='/'} style={({isActive})=>({
                display:'block',padding:'5px 10px',borderRadius:6,fontSize:'0.8rem',fontWeight:500,
                color:isActive?'var(--blue)':(scrolled?'var(--ink60)':'rgba(255,255,255,0.78)'),
                transition:'color 0.2s',
              })}
                onMouseEnter={e=>e.currentTarget.style.color='var(--blue)'}
                onMouseLeave={e=>e.currentTarget.style.color=''}
              >{l}</NavLink></li>
            ))}
          </ul>

          <div style={{display:'flex',gap:8,flexShrink:0}} className="hide-mobile">
            <Link to="/certificate-verification" style={{display:'flex',alignItems:'center',gap:5,padding:'7px 12px',borderRadius:6,border:`1px solid ${scrolled?'var(--rule)':'rgba(255,255,255,0.25)'}`,color:scrolled?'var(--ink40)':'rgba(255,255,255,0.7)',fontSize:'0.76rem',fontWeight:500,transition:'all 0.2s'}}
              onMouseEnter={e=>{e.currentTarget.style.borderColor='var(--blue)';e.currentTarget.style.color='var(--blue)'}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor='';e.currentTarget.style.color=''}}
            ><Shield size={12}/>Verify</Link>
            <Link to="/login" className="btn btn-blue" style={{padding:'7px 16px',fontSize:'0.78rem'}}>
              <LogIn size={12}/>Login
            </Link>
          </div>

          {/* Hamburger */}
          <button onClick={()=>setOpen(!open)} className="hide-desktop" aria-label="Menu" style={{
            width:38,height:38,display:'flex',alignItems:'center',justifyContent:'center',
            borderRadius:8,border:`1px solid ${scrolledOrOpen?'var(--rule)':'rgba(255,255,255,0.3)'}`,
            color:scrolledOrOpen?'var(--ink)':'#fff',transition:'all 0.2s',background:open?'var(--surf)':'transparent',
          }}>
            {open?<X size={18}/>:<Menu size={18}/>}
          </button>
        </div>
      </nav>

      {/* Mobile drawer */}
      <div style={{
        position:'fixed',inset:0,zIndex:999,
        background:'rgba(4,10,20,0.97)',backdropFilter:'blur(18px)',
        display:'flex',flexDirection:'column',padding:'80px 28px 40px',
        transform:open?'translateX(0)':'translateX(100%)',
        transition:'transform 0.32s cubic-bezier(0.4,0,0.2,1)',
        overflowY:'auto',
      }}>
        {LINKS.map(({to,l},i)=>(
          <NavLink key={to} to={to} end={to==='/'} style={({isActive})=>({
            display:'block',padding:'16px 0',
            fontFamily:'var(--serif)',fontSize:'2rem',fontWeight:800,letterSpacing:'-0.02em',
            color:isActive?'var(--blue)':'#fff',
            borderBottom:'1px solid rgba(255,255,255,0.07)',
            animation:`fadeUp 0.4s ${i*0.06}s both`,
          })}>{l}</NavLink>
        ))}
        <div style={{display:'flex',gap:12,marginTop:32}}>
          <Link to="/certificate-verification" className="btn btn-ghost" style={{flex:1,justifyContent:'center',padding:'12px'}}><Shield size={14}/>Verify</Link>
          <Link to="/login" className="btn btn-blue" style={{flex:1,justifyContent:'center',padding:'12px'}}><LogIn size={14}/>Login</Link>
        </div>
      </div>
      <style>{`@keyframes fadeUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}`}</style>
    </>
  );
}
